report.query:
DROP TABLE IF EXISTS all_ns_taxa; DROP TABLE IF EXISTS known_ns_taxa;
SELECT cttl.preferred_taxa_taxon_list_id, cttl.preferred_taxon, cttl.external_key, cttl.taxon_rank_sort_order, cttl.taxon_group INTO TEMP TABLE all_ns_taxa FROM occurrences o JOIN cache_taxa_taxon_lists cttl ON cttl.id = o.taxa_taxon_list_id WHERE o.website_id=8 AND o.deleted=false;
SELECT cttl.preferred_taxa_taxon_list_id, cttl.preferred_taxon, cttl.external_key, cttl.taxon_rank_sort_order, cttl.taxon_group INTO TEMP TABLE known_ns_taxa FROM scratchpad_list_entries sle JOIN cache_taxa_taxon_lists cttl ON cttl.id = sle.entry_id WHERE sle.scratchpad_list_id=12403 AND sle.deleted=false;
SELECT #columns# FROM all_ns_taxa a LEFT JOIN known_ns_taxa k ON k.preferred_taxa_taxon_list_id=a.preferred_taxa_taxon_list_id WHERE k.preferred_taxa_taxon_list_id IS NULL
